import{c as e,Q as d,j as o,m as a}from"./chunks/framework.rlpw0eGz.js";const h=JSON.parse('{"title":"联合索引 (A, B, C) 使用规则","description":"MySQL 联合索引的最左前缀原则、索引失效场景及 EXPLAIN 执行计划分析","frontmatter":{"title":"联合索引 (A, B, C) 使用规则","date":"2026-05-30T00:00:00.000Z","description":"MySQL 联合索引的最左前缀原则、索引失效场景及 EXPLAIN 执行计划分析"},"headers":[],"relativePath":"notes/联合索引 ABC 使用规则.md","filePath":"notes/联合索引 ABC 使用规则.md","lastUpdated":null}'),r={name:"notes/联合索引 ABC 使用规则.md"};function s(c,t,n,l,i,p){return d(),o("div",null,[...t[0]||(t[0]=[a('<h3 id="联合索引-a-b-c-使用规则" tabindex="-1">联合索引 <code>(A, B, C)</code> 使用规则 <a class="header-anchor" href="#联合索引-a-b-c-使用规则" aria-label="Permalink to &quot;联合索引 `(A, B, C)` 使用规则&quot;">​</a></h3><p class="note-date">2026-05-30</p><h4 id="核心原则-最左前缀" tabindex="-1">核心原则：最左前缀 <a class="header-anchor" href="#核心原则-最左前缀" aria-label="Permalink to &quot;核心原则：最左前缀&quot;">​</a></h4><p>索引 <code>KEY idx_abc (A, B, C)</code>，条件必须从 A 开始，中间的列不能跳过。</p><h4 id="条件顺序不影响" tabindex="-1">条件顺序不影响 <a class="header-anchor" href="#条件顺序不影响" aria-label="Permalink to &quot;条件顺序不影响&quot;">​</a></h4><p>MySQL 优化器会做<strong>谓词重排（predicate reordering）</strong>：</p><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="color:#C678DD;">WHERE</span><span style="color:#ABB2BF;"> B </span><span style="color:#56B6C2;">=</span><span style="color:#ABB2BF;"> ? </span><span style="color:#C678DD;">AND</span><span style="color:#ABB2BF;"> A </span><span style="color:#56B6C2;">=</span><span style="color:#ABB2BF;"> ?   </span><span style="color:#7F848E;font-style:italic;">-- 优化器自动改写为 WHERE A = ? AND B = ?</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>EXPLAIN</code> 看 <code>key_len</code> 和 <code>ref</code> 列确认。唯一影响索引使用的不是书写顺序，而是<strong>最左列是否存在</strong>。</p><hr><h4 id="✅-走索引的场景" tabindex="-1">✅ 走索引的场景 <a class="header-anchor" href="#✅-走索引的场景" aria-label="Permalink to &quot;✅ 走索引的场景&quot;">​</a></h4><table tabindex="0"><thead><tr><th>SQL</th><th>使用情况</th></tr></thead><tbody><tr><td><code>WHERE A = ?</code></td><td>用满 A</td></tr><tr><td><code>WHERE A = ? AND B = ?</code></td><td>用满 A、B</td></tr><tr><td><code>WHERE A = ? AND B = ? AND C = ?</code></td><td>用满 A、B、C</td></tr><tr><td><code>WHERE A = ? AND C = ?</code></td><td>只用 A（B 被跳过，C 不生效，索引过滤 + 回表）</td></tr><tr><td><code>WHERE A = ? AND B &gt; ? AND C = ?</code></td><td>A 等值 + B 范围，C 不生效（范围右边列失效）</td></tr><tr><td><code>WHERE A = ? ORDER BY B</code></td><td>走索引排序，无 filesort</td></tr><tr><td><code>WHERE A = ? AND B = ? ORDER BY C</code></td><td>完全有序，无 filesort</td></tr></tbody></table><h4 id="❌-不走索引-或走不全" tabindex="-1">❌ 不走索引（或走不全） <a class="header-anchor" href="#❌-不走索引-或走不全" aria-label="Permalink to &quot;❌ 不走索引（或走不全）&quot;">​</a></h4><table tabindex="0"><thead><tr><th>SQL</th><th>原因</th></tr></thead><tbody><tr><td><code>WHERE B = ?</code></td><td>跳过最左列 A</td></tr><tr><td><code>WHERE C = ?</code></td><td>跳过 A、B</td></tr><tr><td><code>WHERE B = ? AND C = ?</code></td><td>跳过 A</td></tr><tr><td><code>WHERE A LIKE &#39;%xxx&#39;</code></td><td>前导通配符，A 失效</td></tr><tr><td><code>WHERE A = ? OR B = ?</code></td><td>OR 条件两边不走同一索引（除非都覆盖 A）</td></tr></tbody></table><hr><h4 id="关键规则汇总" tabindex="-1">关键规则汇总 <a class="header-anchor" href="#关键规则汇总" aria-label="Permalink to &quot;关键规则汇总&quot;">​</a></h4><ol><li><strong>最左前缀</strong> — 必须从 A 开始</li><li><strong>范围右边失效</strong> — <code>&gt;</code>、<code>&lt;</code>、<code>BETWEEN</code>、<code>LIKE &#39;xxx%&#39;</code> 之后的列不走索引（<code>IN</code>、<code>=</code> 不受影响）</li><li><strong>排序方向一致</strong> — <code>ORDER BY B ASC, C DESC</code> 方向不一致，不走索引排序</li></ol>',16)])])}const B=e(r,[["render",s]]);export{h as __pageData,B as default};
